/**
 * @summary Generate a complete pitch deck narrative
 */
export const getBuildPitchUrl = () => {
  return `/api/pitch/build`;
};

export const buildPitch = async (
  pitchRequest: PitchRequest,
  options?: RequestInit,
): Promise<PitchResult> => {
  return customFetch<PitchResult>(getBuildPitchUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(pitchRequest),
  });
};

export const getBuildPitchMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof buildPitch>>,
    TError,
    { data: BodyType<PitchRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof buildPitch>>,
  TError,
  { data: BodyType<PitchRequest> },
  TContext
> => {
  const mutationKey = ["buildPitch"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof buildPitch>>,
    { data: BodyType<PitchRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return buildPitch(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type BuildPitchMutationResult = NonNullable<
  Awaited<ReturnType<typeof buildPitch>>
>;
export type BuildPitchMutationBody = BodyType<PitchRequest>;
export type BuildPitchMutationError = ErrorType<unknown>;

